const payload = $json.body || $json;
const validSyncs = [
  'employees-to-active-directory',
  'machines-to-telemetry-hub',
  'incidents-to-compliance-db',
  'shift-logs-to-warehouse'
];
if (!payload.syncType || !validSyncs.includes(payload.syncType)) {
  return { error: 'Invalid sync type', validSyncs };
}
return { syncType: payload.syncType, direction: payload.direction || 'outbound', startedAt: new Date().toISOString() };

const { syncType } = $json;
const mappings = {
  'employees-to-active-directory': { source: 'supabase', target: 'ldap', table: 'employees' },
  'machines-to-telemetry-hub': { source: 'supabase', target: 'mqtt', table: 'machines' },
  'incidents-to-compliance-db': { source: 'supabase', target: 'postgres', table: 'safety_incidents' },
  'shift-logs-to-warehouse': { source: 'supabase', target: 'clickhouse', table: 'shift_logs' }
};
return { ...$json, mapping: mappings[syncType], status: 'syncing' };

const response = $json;
return {
  status: 'completed',
  syncType: $json.syncType,
  mapping: response?.mapping || $json.mapping,
  durationMs: Date.now() - new Date($json.startedAt).getTime(),
  completedAt: new Date().toISOString()
};
